export async function increaseTo<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  networkHelpers: NetworkHelpers<ChainTypeT>,
  timestamp: NumberLike | Date,
  duration: Duration,
): Promise<void> {
  const normalizedTimestamp = await toBigInt(
    timestamp instanceof Date
      ? duration.millis(timestamp.valueOf())
      : timestamp,
  );

  await provider.request({
    method: "evm_setNextBlockTimestamp",
    params: [toRpcQuantity(normalizedTimestamp)],
  });

  await networkHelpers.mine();
}

import type { NetworkHelpers, NumberLike } from "../../../../types.js";
import type { ChainType } from "hardhat/types/network";
import type { EthereumProvider } from "hardhat/types/providers";

import { toBigInt, toRpcQuantity } from "../../../conversion.js";

export async function increase<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  networkHelpers: NetworkHelpers<ChainTypeT>,
  amountInSeconds: NumberLike,
): Promise<number> {
  const normalizedAmount = await toBigInt(amountInSeconds);
  const latestTimestamp = await toBigInt(await networkHelpers.time.latest());
  const targetTimestamp = latestTimestamp + normalizedAmount;

  await provider.request({
    method: "evm_setNextBlockTimestamp",
    params: [toRpcQuantity(targetTimestamp)],
  });

  await networkHelpers.mine();

  return await networkHelpers.time.latest();
}

import type { EthereumProvider } from "hardhat/types/providers";

import { HardhatError } from "@nomicfoundation/hardhat-errors";

const chainIdCache = new WeakMap<EthereumProvider, number>();

export async function getChainId(provider: EthereumProvider): Promise<number> {
  const cachedChainId = chainIdCache.get(provider);
  if (cachedChainId !== undefined) {
    return cachedChainId;
  }

  const chainId = Number(await provider.request({ method: "eth_chainId" }));
  chainIdCache.set(provider, chainId);

  return chainId;
}

const DEV_NETWORK_CHAIN_IDS: readonly number[] = [31337, 1337];
export function rejectLocalNetworks(
  networkName: string,
  chainId: number,
): void {
  if (DEV_NETWORK_CHAIN_IDS.includes(chainId)) {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_VERIFY.GENERAL.NETWORK_NOT_SUPPORTED,
      { networkName, chainId },
    );
  }
}

import type { SolcWrapper } from "./solcjs-wrapper.js";

async function readStream(
  stream: NodeJS.ReadStream,
  encoding: BufferEncoding = "utf8",
): Promise<string> {
  stream.setEncoding(encoding);

  return await new Promise((resolve, reject) => {
    let data = "";

    stream.on("data", (chunk) => (data += chunk.toString(encoding)));
    stream.on("end", () => resolve(data));
    stream.on("error", (error) => reject(error));
  });
}

async function getSolcJs(solcJsPath: string): Promise<SolcWrapper> {
  const { default: solcWrapper } = await import("./solcjs-wrapper.js");
  const { default: solc } = await import(solcJsPath);

  return solcWrapper(solc);
}

async function main() {
  const input = await readStream(process.stdin);

  const solcjsPath = process.argv[2];
  const solc = await getSolcJs(solcjsPath);

  const output = solc.compile(input);

  console.log(output);
}

// eslint-disable-next-line no-restricted-syntax -- We intentionally use TLA here
await main().catch((error: unknown) => {
  console.error(error);
  process.exitCode = 1;
});

import type { NewTaskActionFunction } from "../../../types/tasks.js";

import { errorResult, successfulResult } from "../../../utils/result.js";
import {
  isTelemetryAllowed,
  setTelemetryEnabled,
} from "../../cli/telemetry/telemetry-permissions.js";

interface TelemetryActionArguments {
  enable: boolean;
  disable: boolean;
}

const configureTelemetry: NewTaskActionFunction<
  TelemetryActionArguments
> = async ({ enable, disable }) => {
  if (enable && disable) {
    console.error("Cannot enable and disable telemetry at the same time");
    return errorResult();
  }

  if (enable) {
    console.log("Enabling telemetry...");
    await setTelemetryEnabled(true);
  }

  if (disable) {
    console.log("Disabling telemetry...");
    await setTelemetryEnabled(false);
  }

  const consent = await isTelemetryAllowed();

  if (consent) {
    console.log(
      "Telemetry is enabled, to disable it run `npx hardhat telemetry --disable`",
    );
  } else {
    console.log(
      "Telemetry is disabled, to enable it run `npx hardhat telemetry --enable`",
    );
  }

  return successfulResult();
};

export default configureTelemetry;

import type { EncodeFunctionCallFuture } from "../../../types/module.js";
import type { EncodeFunctionCallExecutionState } from "../../execution/types/execution-state.js";
import type {
  ReconciliationContext,
  ReconciliationFutureResult,
} from "../types.js";

import { reconcileArguments } from "../helpers/reconcile-arguments.js";
import { reconcileFunctionName } from "../helpers/reconcile-function-name.js";
import { reconcileStrategy } from "../helpers/reconcile-strategy.js";

export function reconcileNamedEncodeFunctionCall(
  future: EncodeFunctionCallFuture<string, string>,
  executionState: EncodeFunctionCallExecutionState,
  context: ReconciliationContext,
): ReconciliationFutureResult {
  let result = reconcileFunctionName(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  result = reconcileArguments(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  result = reconcileStrategy(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  return { success: true };
}

import type { SendDataFuture } from "../../../types/module.js";
import type { SendDataExecutionState } from "../../execution/types/execution-state.js";
import type {
  ReconciliationContext,
  ReconciliationFutureResultFailure,
} from "../types.js";

import { assertIgnitionInvariant } from "../../utils/assertions.js";
import { findResultForFutureById } from "../../views/find-result-for-future-by-id.js";

import { compare } from "./compare.js";

export function reconcileData(
  future: SendDataFuture,
  exState: SendDataExecutionState,
  context: ReconciliationContext,
): ReconciliationFutureResultFailure | undefined {
  if (typeof future.data === "string" || future.data === undefined) {
    return compare(future, "Data", exState.data, future.data ?? "0x");
  }

  const newData = findResultForFutureById(
    context.deploymentState,
    future.data.id,
  );

  assertIgnitionInvariant(
    typeof newData === "string",
    "Expected data to be a string",
  );

  return compare(future, "Data", exState.data, newData);
}

